repl("Opening and verifying all selected listings", "function parseVehicle_1(name, url, text) {
  const lines = text.split('\n').map(x=>x.trim()).filter(Boolean);
  const heading = (lines.find(l => /^(Used|Certified|New) \d{4}/.test(l)) || name).replace(/^(Used|Certified|New)\s+/, '');
  const yearMatch = heading.match(/\b(19|20)\d{2}\b/);
  const year = yearMatch ? yearMatch[0] : '';
  const makeModel = heading.replace(/^\d{4}\s+/, '');
  const price = (lines.find(l => /^\$\d[\d,]*$/.test(l)) || '').trim();
  const mileage = (lines.find(l => /^\d[\d,]* mi$/.test(l)) || '').trim();
  const sellerIdx = lines.findIndex(l => l === "Seller's info");
  let dealer = '', addr = '', loc = '';
  if (sellerIdx >= 0) {
    dealer = lines[sellerIdx+1] || '';
    addr = lines.slice(sellerIdx+1, sellerIdx+12).find(l => /,\s*[A-Z]{2}\s+\d{5}/.test(l)) || '';
    const cityState = addr.match(/,\s*([^,]+,\s*[A-Z]{2})\s+\d{5}/);
    loc = dealer && cityState ? `${dealer}, ${cityState[1]}` : (dealer || addr);
  }
  return {makeModel, year, price, mileage, dealershipLocation: loc, link: url};
}
